{"path":"/home/user/next-app/components/Todo.tsx","content":"import React, { useState } from 'react';
import { Button } from '@/components/ui/Button';

const Todo: React.FC = () => {
  const [tasks, setTasks] = useState<string[]>([]);
  const [inputValue, setInputValue] = useState<string>('');

  const addTask = () => {
    if (inputValue.trim()) {
      setTasks([...tasks, inputValue]);
      setInputValue('');
    }
  };

  const deleteTask = (taskToDelete: string) => {
    setTasks(tasks.filter(task => task !== taskToDelete));
  };

  return (
    <div className="flex flex-col gap-4 p-4">
      <div className="flex gap-2">
        <input
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          className="border border-gray-300 rounded p-2 flex-grow"
          placeholder="Add a new task"
        />
        <Button onClick={addTask}>Add Task</Button>
      </div>
      <ul className="flex flex-col gap-2">
        {tasks.map((task, index) => (
          <li key={index} className="flex items-center justify-between p-2 border rounded">
            {task}
            <Button variant="destructive" onClick={() => deleteTask(task)}>Delete</Button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default Todo;"}

